27	  if ((f.shipments||[]).some((s)=>!s.deliveredDate&&ms(s.slaDate)<n)) out.shipment=1;
28	  if ((f.regulatoryFlags||[]).some((r)=>r.status==="open")) out.regulatory=1;
29	  if ((f.supportCases||[]).some((c)=>c.status==="open"&&RULES.highSupportSeverities.includes(c.severity))) out.support=1;
30	  const u=f.usage||{};
31	  if (typeof u.priorPeriodUnits==="number"&&u.priorPeriodUnits>0&&u.currentPeriodUnits<=u.priorPeriodUnits*(1-RULES.usageDropFraction)) out.usage=1;
32	  return out;
33	}
34	export function signalsOf(f, now) { const r=firedRisks(f,now); return SIGNAL_ORDER.filter((c)=>r[c]).map((c)=>SIGNAL_NAME[c]); }
35	export function ownersOf(f, now) { const r=firedRisks(f,now); const s=new Set(Object.keys(r).map((c)=>OWNER_FOR[c])); return OWNER_ORDER.filter((o)=>s.has(o)); }
36	export function qualifies(f, now) { return RULES.qualifyingTiers.includes(String(f.account?.tier||"").toLowerCase()) && signalsOf(f,now).length>=1; }
