        ? `${signals.length} signals: ${signals.join(", ")}`
        : "0 signals";
    const topOwner = owners[0] || null;
    const nextStep =
      isQualified && topOwner
        ? `${topOwner} recovery review by 16:00`
        : "Continue standard monitoring.";

    await Promise.all([
      db.collection("workflow_state").deleteMany({}),
      db.collection("owner_tasks").deleteMany({}),
      db.collection("customer_messages").deleteMany({}),
      db.collection("audit_events").deleteMany({}),
    ]);

    await db.collection("workflow_state").insertOne({
      status,
      next_step: nextStep,
      risk_summary: riskSummary,
      updated_at: now,
    });

    if (owners.length > 0) {
      await db.collection("owner_tasks").insertMany(
        owners.map((owner) => ({
          owner_group: owner,
          title: `${owner} recovery review`,
          due_at: now.slice(0, 11) + "16:00:00.000Z",
          status: "open",
        }))
      );
    }

    const customerBody = isQualified
      ? `Your account has been escalated for priority review. Our team has been assigned and is actively working to resolve the identified concerns. A representative will contact you with next steps.`
      : `Your account is currently under standard monitoring. No escalation is required at this time.`;

    await db.collection("customer_messages").insertOne({
      body: customerBody,
      created_at: now,
    });

    await db.collection("audit_events").insertOne({
      event: isQualified ? "escalation_initiated" : "monitoring_check",
      status,
      customer_visible: true,
      created_at: now,
    });
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}
